#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>
#include <math.h>
#include <float.h>

#include "kmeans.h"

#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38
#endif

__device__ float euclid_dist_2_device(float *pt1, float *pt2, int numdims) {
    float ans = 0.0f;
    for (int i = 0; i < numdims; i++) {
        float diff = pt1[i] - pt2[i];
        ans += diff * diff;
    }
    return ans;
}

__device__ int find_nearest_point_device(float *pt, int nfeatures, float **pts, int npts) {
    int index = 0;
    float min_dist = FLT_MAX;

    for (int i = 0; i < npts; i++) {
        float dist = euclid_dist_2_device(pt, pts[i], nfeatures);
        if (dist < min_dist) {
            min_dist = dist;
            index = i;
        }
    }
    return index;
}

__global__ void kmeans_assign_cluster_kernel(float **feature, float **clusters, int *membership, 
                                             int *partial_new_centers_len, float **partial_new_centers,
                                             int npoints, int nclusters, int nfeatures, float *delta_ptr) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i >= npoints) return;

    int tid = blockIdx.y; 

    int index = find_nearest_point_device(feature[i], nfeatures, clusters, nclusters);

    float changed = (membership[i] != index) ? 1.0f : 0.0f;

    if (tid == 0) {
        atomicAdd(delta_ptr, changed);
        membership[i] = index;
    }

    atomicAdd(&partial_new_centers_len[tid * nclusters + index], 1);

    float *local_center = partial_new_centers[tid * nclusters + index];
    for (int j = 0; j < nfeatures; j++) {
        atomicAdd(&local_center[j], feature[i][j]);
    }
}

__global__ void kmeans_update_centers_kernel(float **clusters, float **partial_new_centers, 
                                             int *partial_new_centers_len, int *new_centers_len,
                                             int nclusters, int nfeatures, int nthreads) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i >= nclusters) return;

    float sum_val = 0.0f;
    int count_val = 0;

    for (int t = 0; t < nthreads; t++) {
        float *t_center = partial_new_centers[t * nclusters + i];
        for (int k = 0; k < nfeatures; k++) {
            sum_val += t_center[k];
        }
        count_val += partial_new_centers_len[t * nclusters + i];
    }

    if (count_val > 0) {
        for (int k = 0; k < nfeatures; k++) {
            clusters[i][k] = sum_val / count_val;
        }
    }

    new_centers_len[i] = count_val;
}

__global__ void reset_partial_kernel(int *partial_new_centers_len, float **partial_new_centers, 
                                   int nclusters, int nfeatures, int nthreads) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int total_size = nthreads * nclusters * nfeatures;

    if (idx < nthreads * nclusters) {
        partial_new_centers_len[idx] = 0;
    }

    if (idx < total_size) {
        int t = idx / (nclusters * nfeatures);
        int c = (idx % (nclusters * nfeatures)) / nfeatures;
        int k = idx % nfeatures;
        partial_new_centers[t * nclusters + c][k] = 0.0f;
    }
}

float** kmeans_clustering_cuda(float **feature, int nfeatures, int npoints, int nclusters, float threshold, int *membership) {
    int i, j, k;
    int loop = 0;
    float delta;

    int nthreads = 1; 

    float **clusters;
    clusters = (float**) malloc(nclusters * sizeof(float*));
    clusters[0] = (float*) malloc(nclusters * nfeatures * sizeof(float));
    for (i = 1; i < nclusters; i++)
        clusters[i] = clusters[i-1] + nfeatures;

    int n = 0;
    for (i = 0; i < nclusters; i++) {
        for (j = 0; j < nfeatures; j++)
            clusters[i][j] = feature[n][j];
        n++;
    }

    for (i = 0; i < npoints; i++)
        membership[i] = -1;

    int *new_centers_len = (int*) calloc(nclusters, sizeof(int));

    float **new_centers;
    new_centers = (float**) malloc(nclusters * sizeof(float*));
    new_centers[0] = (float*) calloc(nclusters * nfeatures, sizeof(float));
    for (i = 1; i < nclusters; i++)
        new_centers[i] = new_centers[i-1] + nfeatures;

    int *partial_new_centers_len;
    partial_new_centers_len = (int*) calloc(nthreads * nclusters, sizeof(int));

    float **partial_new_centers_flat;
    partial_new_centers_flat = (float**) malloc(nthreads * nclusters * sizeof(float*));

    float *partial_data = (float*) calloc(nthreads * nclusters * nfeatures, sizeof(float));
    for (i = 0; i < nthreads * nclusters; i++) {
        partial_new_centers_flat[i] = partial_data + i * nfeatures;
    }

    float **d_feature;
    cudaMalloc(&d_feature, npoints * sizeof(float*));
    float *d_feature_data;
    cudaMalloc(&d_feature_data, npoints * nfeatures * sizeof(float));

    float **d_clusters;
    cudaMalloc(&d_clusters, nclusters * sizeof(float*));
    float *d_clusters_data;
    cudaMalloc(&d_clusters_data, nclusters * nfeatures * sizeof(float));

    int *d_membership;
    cudaMalloc(&d_membership, npoints * sizeof(int));

    int *d_partial_len;
    cudaMalloc(&d_partial_len, nthreads * nclusters * sizeof(int));

    float **d_partial_centers;
    cudaMalloc(&d_partial_centers, nthreads * nclusters * sizeof(float*));

    float *d_partial_data;
    cudaMalloc(&d_partial_data, nthreads * nclusters * nfeatures * sizeof(float));

    float *d_delta;
    cudaMalloc(&d_delta, sizeof(float));

    float **d_new_centers;
    cudaMalloc(&d_new_centers, nclusters * sizeof(float*));
    float *d_new_centers_data;
    cudaMalloc(&d_new_centers_data, nclusters * nfeatures * sizeof(float));

    int *d_new_centers_len;
    cudaMalloc(&d_new_centers_len, nclusters * sizeof(int));

    for (i = 0; i < npoints; i++) {
        d_feature_data + i * nfeatures;
    }
    cudaMemcpy(d_feature_data, feature[0], npoints * nfeatures * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(d_feature, &d_feature_data, sizeof(float*), cudaMemcpyHostToDevice); 

    for (i = 0; i < nclusters; i++) {
        d_clusters_data + i * nfeatures;
    }

    do {
        delta = 0.0f;
        cudaMemset(d_delta, 0, sizeof(float));
        cudaMemset(d_partial_len, 0, nthreads * nclusters * sizeof(int));
        cudaMemset(d_partial_data, 0, nthreads * nclusters * nfeatures * sizeof(float));

        dim3 block(256);
        dim3 grid((npoints + block.x - 1) / block.x, nthreads);

        kmeans_assign_cluster_kernel<<<grid, block>>>(d_feature, d_clusters, d_membership, 
                                                      d_partial_len, d_partial_centers,
                                                      npoints, nclusters, nfeatures, d_delta);

        dim3 update_block(256);
        dim3 update_grid((nclusters + update_block.x - 1) / update_block.x);

        kmeans_update_centers_kernel<<<update_grid, update_block>>>(d_clusters, d_partial_centers, 
                                                                    d_partial_len, d_new_centers_len,
                                                                    nclusters, nfeatures, nthreads);

        cudaMemcpy(&delta, d_delta, sizeof(float), cudaMemcpyDeviceToHost);

        loop++;
    } while (delta > threshold && loop < 500);

    cudaMemcpy(clusters[0], d_clusters_data, nclusters * nfeatures * sizeof(float), cudaMemcpyDeviceToHost);

    cudaFree(d_feature);
    cudaFree(d_feature_data);
    cudaFree(d_clusters);
    cudaFree(d_clusters_data);
    cudaFree(d_membership);
    cudaFree(d_partial_len);
    cudaFree(d_partial_centers);
    cudaFree(d_partial_data);
    cudaFree(d_delta);
    cudaFree(d_new_centers);
    cudaFree(d_new_centers_data);
    cudaFree(d_new_centers_len);

    free(new_centers[0]);
    free(new_centers);
    free(new_centers_len);
    free(partial_new_centers_flat);
    free(partial_data);

    return clusters;
}

int cluster(int numObjects, int numAttributes, float **attributes, int nclusters, float threshold, float ***cluster_centres) {
    int *membership;
    float **tmp_cluster_centres;

    membership = (int*) malloc(numObjects * sizeof(int));

    tmp_cluster_centres = kmeans_clustering_cuda(attributes, numAttributes, numObjects, nclusters, threshold, membership);      

    if (*cluster_centres) {
		free((*cluster_centres)[0]);
        free(*cluster_centres);
    }
    *cluster_centres = tmp_cluster_centres;

    free(membership);

    return 0;
}

